changeSet.sql:
-- Atomic document numbering CREATE TABLE document_number_sequences ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, document_type VARCHAR(30) NOT NULL, year INT NOT NULL, counter BIGINT NOT NULL DEFAULT 0, prefix VARCHAR(10) NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0, CONSTRAINT uk_doc_seq_tenant_type_year UNIQUE (tenant_id, document_type, year) );
-- Quotes CREATE TABLE quotes ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, number VARCHAR(30) NOT NULL, customer_id UUID NOT NULL, issue_date DATE NOT NULL, valid_until DATE, status VARCHAR(20) NOT NULL DEFAULT 'DRAFT', currency VARCHAR(3) NOT NULL DEFAULT 'MRU', subtotal NUMERIC(19,2) NOT NULL DEFAULT 0, discount_amount NUMERIC(19,2) NOT NULL DEFAULT 0, tax_amount NUMERIC(19,2) NOT NULL DEFAULT 0, total NUMERIC(19,2) NOT NULL DEFAULT 0, converted_to_order_id UUID, notes VARCHAR(1000), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0, CONSTRAINT uk_quotes_tenant_number UNIQUE (tenant_id, number) );
CREATE INDEX idx_quotes_customer ON quotes(customer_id); CREATE INDEX idx_quotes_status ON quotes(status);
CREATE TABLE quote_lines ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, quote_id UUID NOT NULL, line_number INT NOT NULL, product_id UUID NOT NULL, uom_id UUID NOT NULL, quantity NUMERIC(19,6) NOT NULL, unit_price NUMERIC(19,4) NOT NULL, discount_percent NUMERIC(5,2) NOT NULL DEFAULT 0, tax_rate NUMERIC(5,4) NOT NULL DEFAULT 0, line_total NUMERIC(19,2) NOT NULL, snapshot_name VARCHAR(250), snapshot_sku VARCHAR(64), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0 );
CREATE INDEX idx_quote_lines_quote ON quote_lines(quote_id);
-- Orders CREATE TABLE orders ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, number VARCHAR(30) NOT NULL, customer_id UUID NOT NULL, quote_id UUID, order_date DATE NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'DRAFT', delivery_required BOOLEAN NOT NULL DEFAULT FALSE, currency VARCHAR(3) NOT NULL DEFAULT 'MRU', subtotal NUMERIC(19,2) NOT NULL DEFAULT 0, discount_amount NUMERIC(19,2) NOT NULL DEFAULT 0, tax_amount NUMERIC(19,2) NOT NULL DEFAULT 0, total NUMERIC(19,2) NOT NULL DEFAULT 0, notes VARCHAR(1000), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0, CONSTRAINT uk_orders_tenant_number UNIQUE (tenant_id, number) );
CREATE INDEX idx_orders_customer ON orders(customer_id); CREATE INDEX idx_orders_status ON orders(status);
CREATE TABLE order_lines ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, order_id UUID NOT NULL, line_number INT NOT NULL, product_id UUID NOT NULL, uom_id UUID NOT NULL, quantity NUMERIC(19,6) NOT NULL, unit_price NUMERIC(19,4) NOT NULL, discount_percent NUMERIC(5,2) NOT NULL DEFAULT 0, tax_rate NUMERIC(5,4) NOT NULL DEFAULT 0, line_total NUMERIC(19,2) NOT NULL, snapshot_name VARCHAR(250), snapshot_sku VARCHAR(64), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0 );
CREATE INDEX idx_order_lines_order ON order_lines(order_id);
-- Invoices CREATE TABLE invoices ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, number VARCHAR(30) NOT NULL, customer_id UUID NOT NULL, order_id UUID, issue_date DATE NOT NULL, due_date DATE, status VARCHAR(20) NOT NULL DEFAULT 'DRAFT', currency VARCHAR(3) NOT NULL DEFAULT 'MRU', subtotal NUMERIC(19,2) NOT NULL DEFAULT 0, discount_amount NUMERIC(19,2) NOT NULL DEFAULT 0, tax_amount NUMERIC(19,2) NOT NULL DEFAULT 0, total NUMERIC(19,2) NOT NULL DEFAULT 0, paid_amount NUMERIC(19,2) NOT NULL DEFAULT 0, balance NUMERIC(19,2) NOT NULL DEFAULT 0, payment_terms VARCHAR(100), notes VARCHAR(1000), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0, CONSTRAINT uk_invoices_tenant_number UNIQUE (tenant_id, number) );
CREATE INDEX idx_invoices_customer ON invoices(customer_id); CREATE INDEX idx_invoices_status ON invoices(status); CREATE INDEX idx_invoices_due_date ON invoices(due_date);
CREATE TABLE invoice_lines ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, invoice_id UUID NOT NULL, line_number INT NOT NULL, product_id UUID, uom_id UUID, quantity NUMERIC(19,6) NOT NULL, unit_price NUMERIC(19,4) NOT NULL, discount_percent NUMERIC(5,2) NOT NULL DEFAULT 0, tax_rate NUMERIC(5,4) NOT NULL DEFAULT 0, line_total NUMERIC(19,2) NOT NULL, snapshot_name VARCHAR(250), snapshot_sku VARCHAR(64), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0 );
CREATE INDEX idx_invoice_lines_invoice ON invoice_lines(invoice_id);
-- Credit Notes CREATE TABLE credit_notes ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, number VARCHAR(30) NOT NULL, invoice_id UUID NOT NULL, customer_id UUID NOT NULL, issue_date DATE NOT NULL, reason VARCHAR(500) NOT NULL, amount NUMERIC(19,2) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'DRAFT', applied_to_invoice_id UUID, refunded_amount NUMERIC(19,2) NOT NULL DEFAULT 0, currency VARCHAR(3) NOT NULL DEFAULT 'MRU', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0, CONSTRAINT uk_credit_notes_tenant_number UNIQUE (tenant_id, number) );
CREATE INDEX idx_credit_notes_invoice ON credit_notes(invoice_id);
